import { useEffect, useRef, useState } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { fetchAdminAlerts, fetchMySOSHistory } from '../../api/sos.api';
import rescueLinkLogo from './RescueLink_Logo.png';

function NavBar() {
  const { isAuthenticated, role, logout, user } = useAuth();
  const navigate = useNavigate();
  const [darkMode, setDarkMode] = useState(() => localStorage.getItem('theme') === 'dark');
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [notifOpen, setNotifOpen] = useState(false);
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [notifLoading, setNotifLoading] = useState(false);
  const notifRef = useRef(null);

  useEffect(() => {
    document.body.classList.toggle('dark-mode', darkMode);
    localStorage.setItem('theme', darkMode ? 'dark' : 'light');
  }, [darkMode]);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 8);
    onScroll();
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    const closeOnOutsideClick = (event) => {
      if (notifRef.current && !notifRef.current.contains(event.target)) {
        setNotifOpen(false);
      }
    };
    document.addEventListener('mousedown', closeOnOutsideClick);
    return () => document.removeEventListener('mousedown', closeOnOutsideClick);
  }, []);

  useEffect(() => {
    if (!isAuthenticated || !user?.id) {
      setNotifications([]);
      setUnreadCount(0);
      return undefined;
    }

    const loadNotifications = async ({ markRead } = { markRead: false }) => {
      try {
        setNotifLoading(true);
        const items = role === 'ADMIN'
          ? await fetchAdminAlerts()
          : await fetchMySOSHistory(user.id);

        const normalized = (items || []).slice(0, 6).map((item) => ({
          id: item.id,
          title: role === 'ADMIN' ? 'New SOS Alert' : 'SOS Status Update',
          message: role === 'ADMIN'
            ? `Alert from user ${item.userId || 'N/A'} at ${item.location || 'Unknown location'}`
            : `Status: ${item.status || 'ACTIVE'} at ${item.location || 'Unknown location'}`,
          createdAt: item.createdAt
        }));
        setNotifications(normalized);
        if (!markRead) {
          setUnreadCount(normalized.length);
        }
      } catch {
        // keep silent; bell should not break navigation
      } finally {
        setNotifLoading(false);
      }
    };

    loadNotifications();
    const id = setInterval(() => {
      if (!notifOpen) {
        loadNotifications();
      }
    }, 30000);

    return () => clearInterval(id);
  }, [isAuthenticated, notifOpen, role, user?.id]);

  const toggleNotifications = async () => {
    const nextOpen = !notifOpen;
    setNotifOpen(nextOpen);
    if (nextOpen) {
      setUnreadCount(0);
      try {
        setNotifLoading(true);
        const items = role === 'ADMIN'
          ? await fetchAdminAlerts()
          : await fetchMySOSHistory(user?.id);
        const normalized = (items || []).slice(0, 6).map((item) => ({
          id: item.id,
          title: role === 'ADMIN' ? 'New SOS Alert' : 'SOS Status Update',
          message: role === 'ADMIN'
            ? `Alert from user ${item.userId || 'N/A'} at ${item.location || 'Unknown location'}`
            : `Status: ${item.status || 'ACTIVE'} at ${item.location || 'Unknown location'}`,
          createdAt: item.createdAt
        }));
        setNotifications(normalized);
      } catch {
        // keep previously loaded notifications
      } finally {
        setNotifLoading(false);
      }
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className={`navbar navbar-expand-lg sticky-top bg-white border-bottom ${scrolled ? 'nav-scrolled' : 'shadow-sm'}`}>
      <div className='container'>
        <Link className='navbar-brand fw-bold text-danger' to='/'>
          <span className='d-flex align-items-center'>
            <img
              src={rescueLinkLogo}
              alt='RescueLink logo'
              className='brand-logo'
              onError={(e) => {
                e.currentTarget.style.display = 'none';
              }}
            />
          </span>
        </Link>

        <button
          className='navbar-toggler'
          type='button'
          data-bs-toggle='collapse'
          data-bs-target='#mainNav'
          aria-controls='mainNav'
          aria-expanded='false'
          aria-label='Toggle navigation'
        >
          <span className='navbar-toggler-icon' />
        </button>

        <div className='collapse navbar-collapse' id='mainNav'>
          <div className='navbar-nav ms-auto align-items-lg-center gap-lg-2'>
            <NavLink className='nav-link' to='/'>Home</NavLink>
            <NavLink className='nav-link' to='/hospitals'>Hospitals</NavLink>
            <NavLink className='nav-link' to='/donors'>Donors</NavLink>

            {isAuthenticated ? (
              <>
                <NavLink className='nav-link' to={role === 'ADMIN' ? '/admin' : '/dashboard'}>
                  Dashboard
                </NavLink>
                <button
                  type='button'
                  className='btn btn-sm btn-outline-secondary'
                  onClick={() => setDarkMode((prev) => !prev)}
                  aria-label='Toggle dark mode'
                >
                  {darkMode ? 'Light' : 'Dark'}
                </button>
                <div className='position-relative d-inline-block' ref={notifRef}>
                  <button
                    type='button'
                    className='btn btn-sm btn-outline-secondary'
                    aria-label='Notifications'
                    onClick={toggleNotifications}
                  >
                    🔔
                  </button>
                  {unreadCount > 0 && (
                    <span className='position-absolute top-0 start-100 translate-middle badge rounded-pill text-bg-danger'>
                      {unreadCount}
                    </span>
                  )}
                  {notifOpen && (
                    <div className='position-absolute end-0 mt-2 card card-soft p-2' style={{ minWidth: 320, zIndex: 1081 }}>
                      <p className='fw-semibold mb-2'>Notifications</p>
                      {notifLoading && <p className='small text-muted mb-0'>Loading...</p>}
                      {!notifLoading && notifications.length === 0 && (
                        <p className='small text-muted mb-0'>No notifications yet.</p>
                      )}
                      {!notifLoading && notifications.length > 0 && (
                        <div className='d-grid gap-2'>
                          {notifications.map((item) => (
                            <div key={item.id} className='border rounded p-2'>
                              <p className='mb-1 fw-semibold small'>{item.title}</p>
                              <p className='mb-1 small'>{item.message}</p>
                              <small className='text-muted'>
                                {item.createdAt ? new Date(item.createdAt).toLocaleString() : 'Just now'}
                              </small>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                </div>
                <div className='position-relative'>
                  <button className='btn btn-outline-secondary btn-sm rounded-pill' onClick={() => setMenuOpen((prev) => !prev)}>
                    {user?.name?.split(' ')[0] || 'User'}
                  </button>
                  {menuOpen && (
                    <div className='position-absolute end-0 mt-2 card card-soft p-2' style={{ minWidth: 180, zIndex: 1081 }}>
                      <NavLink className='dropdown-item' to='/profile' onClick={() => setMenuOpen(false)}>Profile</NavLink>
                      <button className='dropdown-item text-danger' onClick={handleLogout}>Logout</button>
                    </div>
                  )}
                </div>
              </>
            ) : (
              <>
                <button
                  type='button'
                  className='btn btn-sm btn-outline-secondary'
                  onClick={() => setDarkMode((prev) => !prev)}
                  aria-label='Toggle dark mode'
                >
                  {darkMode ? 'Light' : 'Dark'}
                </button>
                <NavLink className='btn btn-outline-danger btn-sm' to='/login'>Login</NavLink>
                <NavLink className='btn btn-danger btn-sm' to='/register'>Register</NavLink>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default NavBar;
